public class EstruturasCondicionais {    public static void main(String[] args) {        int idade = 10;        boolean isAutorizadoComprarBebida = idade >= 18;        if (isAutorizadoComprarBebida){            System.out.println("Autoriza o arbitro...");        } else if (!(isAutorizadoComprarBebida)) {            System.out.println("Você não pode comprar bebida ainda.");        }    }}